"use client";

import { useState, type CSSProperties, type ReactNode } from "react";

import { SettingsSidebar } from "./settings-sidebar";
import { SettingsHeader } from "./settings-header";
import { SettingsBottomNav } from "./settings-bottom-nav";
import { SettingsBottomDrawer } from "./settings-bottom-drawer";
import { SidebarInset, SidebarProvider } from "@/components/ui/sidebar";
import { TooltipProvider } from "@/components/ui/tooltip";

interface SettingsLayoutProps {
  children: ReactNode;
}

export function SettingsLayout({ children }: SettingsLayoutProps) {
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);

  return (
    <TooltipProvider>
      <SidebarProvider
        style={
          {
            "--sidebar-width": "16rem",
            "--header-height": "calc(var(--spacing) * 12)",
          } as CSSProperties
        }
        className="h-svh overflow-hidden"
      >
        <SettingsSidebar variant="sidebar" />
        <SidebarInset className="min-h-svh rounded-none shadow-none">
          <SettingsHeader />
          <main className="flex flex-1 flex-col overflow-y-auto overflow-x-hidden pb-20 md:pb-0">
            {children}
          </main>
        </SidebarInset>
        <SettingsBottomNav onMoreClick={() => setIsDrawerOpen(true)} />
        <SettingsBottomDrawer
          open={isDrawerOpen}
          onClose={() => setIsDrawerOpen(false)}
        />
      </SidebarProvider>
    </TooltipProvider>
  );
}

"use client";

import * as React from "react";
import Link from "next/link";
import { ViewSidebarLeftIcon, ArrowLeft02Icon } from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";

import { usePathname, useRouter } from "next/navigation";
import {
  Sidebar,
  SidebarContent,
  SidebarFooter,
  SidebarHeader,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
  SidebarGroup,
  SidebarGroupLabel,
  SidebarGroupContent,
  useSidebar,
} from "@/components/ui/sidebar";
import { cn } from "@/lib/utils";
import { settingsNavMain } from "./settings-nav-config";

export function SettingsSidebar({ ...props }: React.ComponentProps<typeof Sidebar>) {
  const { state, toggleSidebar } = useSidebar();
  const pathname = usePathname();
  const router = useRouter();

  return (
    <Sidebar
      collapsible="icon"
      className="h-svh overflow-hidden border-r"
      {...props}
    >
      <SidebarHeader className="border-b">
        <SidebarMenu>
          <SidebarMenuItem>
            <SidebarMenuButton
              onClick={() => router.back()}
              className="data-[slot=sidebar-menu-button]:p-1.5!"
            >
              <HugeiconsIcon
                icon={ArrowLeft02Icon}
                size={20}
                strokeWidth={1.5}
              />
              <span className="text-base font-semibold">
                Back
              </span>
            </SidebarMenuButton>
          </SidebarMenuItem>
        </SidebarMenu>
      </SidebarHeader>
      <SidebarContent>
        <SidebarGroup>
          <SidebarGroupLabel>Settings Menu</SidebarGroupLabel>
          <SidebarGroupContent>
            <SidebarMenu>
              {settingsNavMain.map((item) => (
                <SidebarMenuItem key={item.title}>
                  <SidebarMenuButton 
                    asChild 
                    tooltip={item.title}
                    isActive={pathname === item.url}
                  >
                    <Link href={item.url}>
                      <HugeiconsIcon icon={item.icon} size={20} strokeWidth={1.5} />
                      <span>{item.title}</span>
                    </Link>
                  </SidebarMenuButton>
                </SidebarMenuItem>
              ))}
            </SidebarMenu>
          </SidebarGroupContent>
        </SidebarGroup>
      </SidebarContent>
      <SidebarFooter>
        <SidebarMenu>
          <SidebarMenuItem>
            <SidebarMenuButton
              onClick={toggleSidebar}
              tooltip={
                state === "collapsed" ? "Expand sidebar" : "Collapse sidebar"
              }
            >
              <HugeiconsIcon
                icon={ViewSidebarLeftIcon}
                size={20}
                strokeWidth={1.5}
                className={cn(
                  "transition-transform duration-200 ease-in-out",
                  state === "collapsed" && "rotate-180",
                )}
              />
              {state === "collapsed" ? null : <span>Collapse menu</span>}
            </SidebarMenuButton>
          </SidebarMenuItem>
        </SidebarMenu>
      </SidebarFooter>
    </Sidebar>
  );
}

"use client";

import { usePathname } from "next/navigation";
import { ThemeToggle } from "../layout/theme-toggle";
import { NavUser } from "../layout/nav-user";
import { HeaderNotifications } from "../dashboard/header-notifications";
import { settingsNavMain } from "./settings-nav-config";

const headerUser = {
  name: "murgo",
  email: "m@example.com",
  avatar: "https://api.dicebear.com/9.x/avataaars/svg?seed=murgo",
};

export function SettingsHeader() {
  const pathname = usePathname();

  // Trouver le titre de la section actuelle
  const currentSection = settingsNavMain.find(item => item.url === pathname);
  const title = currentSection?.title || "Settings";

  return (
    <header className="sticky top-0 z-20 flex h-(--header-height) shrink-0 items-center gap-2 border-b bg-background/95 backdrop-blur transition-[width,height] ease-linear group-has-data-[collapsible=icon]/sidebar-wrapper:h-(--header-height)">
      <div className="flex w-full items-center gap-2 px-3 sm:px-4 lg:px-6">
        <h1 className="text-base font-medium text-foreground">{title}</h1>
        <div className="ml-auto flex items-center gap-2">
          <HeaderNotifications />
          <ThemeToggle />
          <NavUser user={headerUser} compact />
        </div>
      </div>
    </header>
  );
}

"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { Menu01Icon } from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";

import { cn } from "@/lib/utils";
import { settingsNavMain, backToDashboard } from "./settings-nav-config";

interface SettingsBottomNavProps {
  onMoreClick?: () => void;
}

export function SettingsBottomNav({ onMoreClick }: SettingsBottomNavProps) {
  const pathname = usePathname();

  return (
    <nav className="fixed right-0 bottom-0 left-0 z-50 border-t border-border bg-background md:hidden">
      <div className="grid grid-cols-5">
        <Link
          href={backToDashboard.url}
          className="flex flex-col items-center gap-1 px-2 py-2 text-muted-foreground hover:text-primary transition-colors"
        >
          <HugeiconsIcon icon={backToDashboard.icon} size={22} strokeWidth={1.5} />
          <span className="text-[10px]">Dashboard</span>
        </Link>

        {settingsNavMain.map((item) => {
          const isActive = pathname === item.url;

          return (
            <Link
              key={item.url}
              href={item.url}
              className={cn(
                "flex flex-col items-center gap-1 px-2 py-2 transition-colors",
                isActive ? "text-primary font-medium" : "text-muted-foreground hover:text-primary",
              )}
            >
              <HugeiconsIcon icon={item.icon} size={22} strokeWidth={1.5} />
              <span className="text-[10px] truncate w-full text-center">
                {item.label}
              </span>
            </Link>
          );
        })}

        <button
          type="button"
          onClick={onMoreClick}
          className="flex flex-col items-center gap-1 px-2 py-2 text-muted-foreground hover:text-primary transition-colors"
        >
          <HugeiconsIcon icon={Menu01Icon} size={22} strokeWidth={1.5} />
          <span className="text-[10px]">More</span>
        </button>
      </div>
    </nav>
  );
}

import {
  UserAccountIcon,
  Settings03Icon,
  InternetIcon,
  ArrowLeft02Icon,
  DashboardSquare01Icon,
} from "@hugeicons/core-free-icons";
import type { IconSvgElement } from "@hugeicons/react";

export interface SettingsNavItem {
  title: string;
  label: string;
  url: string;
  icon: IconSvgElement;
}

export const settingsNavMain: SettingsNavItem[] = [
  {
    title: "Profile Management",
    label: "Profile",
    url: "/settings/profile",
    icon: UserAccountIcon,
  },
  {
    title: "Account Settings",
    label: "Account",
    url: "/settings/account",
    icon: Settings03Icon,
  },
  {
    title: "Global Configuration",
    label: "Global",
    url: "/settings/global",
    icon: InternetIcon,
  },
];

export const backToDashboard = {
  title: "Back to Dashboard",
  url: "/dashboard",
  icon: DashboardSquare01Icon,
};

import { SettingsLayout } from "@/components/settings/settings-layout";
import { redirect } from "next/navigation";

export default function Layout({ children }: { children: React.ReactNode }) {
  return <SettingsLayout>{children}</SettingsLayout>;
}

import { redirect } from "next/navigation";

export default function SettingsPage() {
  redirect("/settings/profile");
}

import * as React from "react"

import { cn } from "@/lib/utils"

function Textarea({ className, ...props }: React.ComponentProps<"textarea">) {
  return (
    <textarea
      data-slot="textarea"
      className={cn(
        "flex field-sizing-content min-h-16 w-full rounded-lg border border-input bg-transparent px-2.5 py-2 text-base transition-colors outline-none placeholder:text-muted-foreground disabled:cursor-not-allowed disabled:bg-input/50 disabled:opacity-50 aria-invalid:border-destructive md:text-sm dark:bg-input/30 dark:disabled:bg-input/80 dark:aria-invalid:border-destructive/50",
        className
      )}
      {...props}
    />
  )
}

export { Textarea }
